#include <bits/stdc++.h>
using namespace std;
string mid,last;
int p[26];
void dfs(int l,int r){
    if(l>r)
        return;
    cout<<last[r];
    int m=r;
    for(int i=l;i<r;i++)
        if(p[last[i]-'A']>p[last[r]-'A']){
            m=i;
            break;
        }
    dfs(l,m-1);
    dfs(m,r-1);
}
int main(){
    cin>>mid>>last;
    mid=" "+mid;
    last=" "+last;
    for(int i=1;i<mid.size();i++)
        p[mid[i]-'A']=i;
    dfs(1,last.size()-1);
    return 0;
}
